/**
 * Home / Dashboard Page
 * ======================
 * Landing page with stats, recent activity, and quick actions.
 */

import React from "react";
import { Link } from "react-router-dom";
import { PageContainer, PageHeader } from "~/components/layout";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@afenda/ui";
import { Button } from "@afenda/ui";
import { Badge } from "@afenda/ui";
import { ArrowRight, Plus, FileText, ShoppingCart, Package } from "lucide-react";

export default function HomePage() {
  return (
    <PageContainer>
      <PageHeader
        title="Dashboard"
        description="Welcome to AFENDA Meta-UI Platform"
      />

      {/* Stats Overview */}
      <div className="grid gap-6 md:grid-cols-3 mb-8">
        <Card>
          <CardHeader className="pb-3">
            <CardDescription>Total Partners</CardDescription>
            <CardTitle className="text-3xl">127</CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-sm text-muted-foreground">
              <span className="text-green-600 font-medium">+12%</span> from last month
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-3">
            <CardDescription>Sales Orders</CardDescription>
            <CardTitle className="text-3xl">89</CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-sm text-muted-foreground">
              <span className="text-green-600 font-medium">+8%</span> from last month
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-3">
            <CardDescription>Products</CardDescription>
            <CardTitle className="text-3xl">243</CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-sm text-muted-foreground">
              <span className="text-blue-600 font-medium">+24</span> new this month
            </p>
          </CardContent>
        </Card>
      </div>

      {/* Quick Actions */}
      <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
        <Card>
          <CardHeader>
            <div className="flex items-center justify-between">
              <CardTitle className="flex items-center gap-2">
                <FileText className="w-5 h-5" />
                Partners
              </CardTitle>
              <Badge>127</Badge>
            </div>
            <CardDescription>
              Manage customers, suppliers, and business relationships
            </CardDescription>
          </CardHeader>
          <CardContent className="flex gap-2">
            <Button asChild className="flex-1">
              <Link to="/sales/partner">
                View All
                <ArrowRight className="w-4 h-4 ml-2" />
              </Link>
            </Button>
            <Button asChild variant="outline">
              <Link to="/sales/partner/new">
                <Plus className="w-4 h-4" />
              </Link>
            </Button>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <div className="flex items-center justify-between">
              <CardTitle className="flex items-center gap-2">
                <ShoppingCart className="w-5 h-5" />
                Sales Orders
              </CardTitle>
              <Badge variant="secondary">89</Badge>
            </div>
            <CardDescription>
              Track and manage customer orders and quotations
            </CardDescription>
          </CardHeader>
          <CardContent className="flex gap-2">
            <Button asChild className="flex-1">
              <Link to="/sales/sales_order">
                View All
                <ArrowRight className="w-4 h-4 ml-2" />
              </Link>
            </Button>
            <Button asChild variant="outline">
              <Link to="/sales/sales_order/new">
                <Plus className="w-4 h-4" />
              </Link>
            </Button>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <div className="flex items-center justify-between">
              <CardTitle className="flex items-center gap-2">
                <Package className="w-5 h-5" />
                Products
              </CardTitle>
              <Badge variant="secondary">243</Badge>
            </div>
            <CardDescription>
              Manage product catalog, pricing, and inventory
            </CardDescription>
          </CardHeader>
          <CardContent className="flex gap-2">
            <Button asChild className="flex-1">
              <Link to="/sales/product">
                View All
                <ArrowRight className="w-4 h-4 ml-2" />
              </Link>
            </Button>
            <Button asChild variant="outline">
              <Link to="/sales/product/new">
                <Plus className="w-4 h-4" />
              </Link>
            </Button>
          </CardContent>
        </Card>
      </div>

      {/* Recent Activity (placeholder) */}
      <Card className="mt-8">
        <CardHeader>
          <CardTitle>Recent Activity</CardTitle>
          <CardDescription>Latest changes across all modules</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="space-y-3">
            <div className="flex items-center gap-3 text-sm">
              <Badge variant="outline">Sales Order</Badge>
              <span className="text-muted-foreground">SO-2026-0042 created by Admin User</span>
              <span className="ml-auto text-xs text-muted-foreground">2 hours ago</span>
            </div>
            <div className="flex items-center gap-3 text-sm">
              <Badge variant="outline">Partner</Badge>
              <span className="text-muted-foreground">Acme Corp updated by Admin User</span>
              <span className="ml-auto text-xs text-muted-foreground">5 hours ago</span>
            </div>
            <div className="flex items-center gap-3 text-sm">
              <Badge variant="outline">Product</Badge>
              <span className="text-muted-foreground">Widget Pro added by Admin User</span>
              <span className="ml-auto text-xs text-muted-foreground">1 day ago</span>
            </div>
          </div>
        </CardContent>
      </Card>
    </PageContainer>
  );
}
